const staticData = $getWorkflowStaticData('global');
const sinceToken = staticData.matrixSinceToken || '';
return [{ json: { sinceToken } }];

const ROOM_MAP = {
  '!PVkZvHgyrtBVEbgpRt:matrix.example.net': 'chatops',
  '!iXTnQsFJahUquYPDdG:matrix.example.net': 'cubeos',
  '!miZJJDwFQZDkuMcBqL:matrix.example.net': 'meshsat',
  '!AOMuEtXGyzGFLgObKN:matrix.example.net': 'infra',
  '!NKosBPujbWMevzHaaM:matrix.example.net': 'infra-gr',
  '!HdUfKpzHeplqBOYvwY:matrix.example.net': 'learning'
};

// IFRNLLEI01PRD-653 multi-operator. Merge every teacher DM room
// (from teacher_operator_dm.dm_room_id via the Fetch Operator DMs
// SSH step) into ROOM_MAP as 'teacher-dm'. Falls back gracefully
// when the SSH output is empty.
try {
  const dmOut = ($('Fetch Operator DMs').first().json.stdout || '')
    .split('\n').map(s => s.trim()).filter(s => s);
  for (const rid of dmOut) {
    ROOM_MAP[rid] = 'teacher-dm';
  }
} catch (e) {
  // No Fetch Operator DMs node output available — continue with the
  // static ROOM_MAP (bridge still works for the site rooms).
}
const MONITORED_ROOMS = Object.keys(ROOM_MAP);
const DEFAULT_ROOM = '!PVkZvHgyrtBVEbgpRt:matrix.example.net';
const botUserId = '@claude:matrix.example.net';
const openclawUserId = '@openclaw:matrix.example.net';

const AUTHORIZED_SENDERS = [
  '@dominicus:matrix.example.net'
];

// IFRNLLEI01PRD-653: #learning room uses membership-based auth
// (enforced by teacher-agent.py via Matrix API). Let its messages
// through the early sender filter so they reach Detect Command.
const LEARNING_ROOM_ID = '!HdUfKpzHeplqBOYvwY:matrix.example.net';
function isAllowed(senderMxid, roomId) {
  if (AUTHORIZED_SENDERS.includes(senderMxid)) return true;
  if (roomId === LEARNING_ROOM_ID) return true;
  return false;
}


// \u2500\u2500 INPUT SANITIZATION (Pattern 18 \u2014 Guardrails) \u2500\u2500
const INJECTION_PATTERNS = [
  /ignore (?:all )?(?:previous|above|prior) instructions/i,
  /you are now (?:a |an )?(?:new |different )?(?:AI|assistant|agent|system)/i,
  /system:\s*you are/i,
  /\[SYSTEM\]/i,
  /\<\|(?:im_start|system|endoftext)\|\>/i,
  /forget (?:everything|all|your) (?:instructions|rules|constraints)/i,
  /override (?:your |all )?(?:safety|rules|instructions|constraints)/i,
  /do not follow (?:your|the) (?:instructions|rules)/i,
  /pretend (?:you are|to be|that)/i,
  /act as (?:if|though) you (?:have no|don't have) (?:rules|restrictions)/i,
];

function sanitizeInput(text) {
  if (!text) return { clean: text, injectionDetected: false };
  let clean = text;
  let detected = false;
  for (const pattern of INJECTION_PATTERNS) {
    if (pattern.test(clean)) {
      detected = true;
      clean = clean.replace(pattern, '[SANITIZED]');
    }
  }
  // Strip zero-width chars and Unicode control chars (common injection technique)
  clean = clean.replace(/[\u200B-\u200F\u2028-\u202F\u2060-\u206F\uFEFF]/g, '');
  return { clean, injectionDetected: detected };
}

const THUMBS_UP = ['\ud83d\udc4d', '\ud83d\udc4d\ufe0f'];
const THUMBS_DOWN = ['\ud83d\udc4e', '\ud83d\udc4e\ufe0f'];
const REACTION_KEYS = [...THUMBS_UP, ...THUMBS_DOWN];

const staticData = $getWorkflowStaticData('global');
const syncResponse = $input.first().json;

if (!syncResponse.next_batch) {
  return [{ json: { hasMessages: false, messages: [], messageText: '', sourceRoom: DEFAULT_ROOM, mentionsClaude: false, mentionsOpenclaw: false } }];
}

const previousToken = staticData.matrixSinceToken;
staticData.matrixSinceToken = syncResponse.next_batch;

if (!staticData.sentMessageCache) staticData.sentMessageCache = {};
if (!staticData.pollCache) staticData.pollCache = {};
if (!staticData.pendingApprovals) staticData.pendingApprovals = {};

const joinedRooms = syncResponse.rooms?.join || {};

for (const roomId of MONITORED_ROOMS) {
  const roomData = joinedRooms[roomId];
  if (!roomData) continue;
  const events = roomData.timeline?.events || [];
  for (const e of events) {
    if (e.type === 'm.room.message' && e.sender === botUserId && e.event_id) {
      staticData.sentMessageCache[e.event_id] = {
        body: e.content?.body || '',
        room: roomId,
        ts: e.origin_server_ts || 0
      };
      const msgBody = e.content?.body || '';
      if (/awaiting approval|waiting for.*approval|react.*approv|reply.*approved/i.test(msgBody)) {
        const issueMatch = msgBody.match(/\[([A-Z0-9]+-\d+)\]/);
        if (issueMatch) {
          const flapMatch = msgBody.match(/\[FLAPPING x(\d+)\]/);
          staticData.pendingApprovals[e.event_id] = {
            issueId: issueMatch[1],
            roomId: roomId,
            timestamp: e.origin_server_ts || Date.now(),
            reminded: false,
            flapCount: flapMatch ? parseInt(flapMatch[1]) : 0
          };
        }
      }
    }
    if ((e.type === 'org.matrix.msc3381.poll.start' || e.type === 'm.poll.start') && e.sender === botUserId && e.event_id) {
      const pollData = e.content?.['org.matrix.msc3381.poll.start'] || e.content?.['m.poll.start'] || {};
      const answers = (pollData.answers || []).map(a => ({
        id: a.id || a['m.id'] || '',
        body: a['org.matrix.msc1767.text'] || a['org.matrix.msc3381.text.body'] || a['m.text'] || a.id || ''
      }));
      staticData.pollCache[e.event_id] = {
        question: pollData.question?.['org.matrix.msc1767.text'] || pollData.question?.body || '',
        answers,
        room: roomId,
        ts: e.origin_server_ts || 0
      };
    }
  }
}

for (const cache of [staticData.sentMessageCache, staticData.pollCache]) {
  const keys = Object.keys(cache);
  if (keys.length > 100) {
    const sorted = keys.sort((a, b) => cache[a].ts - cache[b].ts);
    for (let i = 0; i < sorted.length - 100; i++) {
      delete cache[sorted[i]];
    }
  }
}

for (const [eid, pa] of Object.entries(staticData.pendingApprovals)) {
  if (Date.now() - pa.timestamp > 3600000) delete staticData.pendingApprovals[eid];
}

if (!previousToken) {
  return [{ json: { hasMessages: false, messages: [], messageText: '', sourceRoom: DEFAULT_ROOM, mentionsClaude: false, mentionsOpenclaw: false } }];
}

const lastProcessedTs = staticData.lastProcessedTimestamp || 0;

let allUserMessages = [];
let sourceRoom = DEFAULT_ROOM;

for (const roomId of MONITORED_ROOMS) {
  const roomData = joinedRooms[roomId];
  if (!roomData) continue;
  const events = roomData.timeline?.events || [];
  const userMsgs = events.filter(e => {
    if (e.type !== 'm.room.message') return false;
    if (e.content?.msgtype !== 'm.text') return false;
    if (e.sender === botUserId || e.sender === openclawUserId) return false;
    if (!AUTHORIZED_SENDERS.includes(e.sender)) return false;
    if ((e.origin_server_ts || 0) <= lastProcessedTs) return false;
    if (!isAllowed(e.sender, roomId)) return false;
    return true;
  });
  for (const msg of userMsgs) {
    allUserMessages.push({ ...msg, _roomId: roomId });
  }
}

for (const roomId of MONITORED_ROOMS) {
  const roomData = joinedRooms[roomId];
  if (!roomData) continue;
  const events = roomData.timeline?.events || [];
  for (const e of events) {
    if (e.type !== 'm.reaction') continue;
    if (!isAllowed(e.sender, roomId)) continue;
    if ((e.origin_server_ts || 0) <= lastProcessedTs) continue;

    const key = e.content?.['m.relates_to']?.key;
    if (!REACTION_KEYS.includes(key)) continue;

    const targetEventId = e.content['m.relates_to'].event_id;
    const cached = staticData.sentMessageCache?.[targetEventId];
    if (!cached) continue;

    const action = THUMBS_UP.includes(key) ? 'approved' : 'rejected';
    const targetText = cached.body.length > 300
      ? cached.body.substring(0, 300) + '...'
      : cached.body;
    const body = 'User ' + action + ': ' + targetText;

    if (staticData.pendingApprovals?.[targetEventId]) {
      delete staticData.pendingApprovals[targetEventId];
    }

    allUserMessages.push({
      type: 'm.reaction',
      sender: e.sender,
      origin_server_ts: e.origin_server_ts,
      content: { body, msgtype: 'm.text' },
      _roomId: roomId,
      _isReaction: true,
      _reactionType: action
    });
  }
}

for (const roomId of MONITORED_ROOMS) {
  const roomData = joinedRooms[roomId];
  if (!roomData) continue;
  const events = roomData.timeline?.events || [];
  for (const e of events) {
    if (e.type !== 'org.matrix.msc3381.poll.response' && e.type !== 'm.poll.response') continue;
    if (!isAllowed(e.sender, roomId)) continue;
    if ((e.origin_server_ts || 0) <= lastProcessedTs) continue;

    const relatesTo = e.content?.['m.relates_to'] || {};
    const pollEventId = relatesTo.event_id;
    const cachedPoll = staticData.pollCache?.[pollEventId];
    if (!cachedPoll) continue;

    const responseData = e.content?.['org.matrix.msc3381.poll.response'] || e.content?.['m.poll.response'] || {};
    const selectedIds = responseData.answers || [];

    const selectedOptions = selectedIds.map(id => {
      const answer = cachedPoll.answers.find(a => a.id === id);
      return answer ? answer.body : id;
    });

    // Approval-poll detection — answer ids of approve|reject|investigate mean
    // this was a Check-Approval-Timeouts-generated poll, not a plan poll.
    const APPROVAL_POLL_IDS = new Set(['approve','reject','investigate']);
    const isApprovalPoll = selectedIds.some(id => APPROVAL_POLL_IDS.has(id));
    const approvalIssueMatch = cachedPoll.question.match(/\b([A-Z0-9]+-\d+)\b/);
    const approvalIssueId = approvalIssueMatch ? approvalIssueMatch[1] : '';
    // Clear matching pendingApproval entry (any event_id whose issueId matches)
    if (isApprovalPoll && approvalIssueId) {
      for (const [eid, pa] of Object.entries(staticData.pendingApprovals || {})) {
        if (pa.issueId === approvalIssueId) delete staticData.pendingApprovals[eid];
      }
    }

    const isOther = selectedOptions.some(o => /other/i.test(o));
    let body;
    let reactionType = 'approved';

    if (isApprovalPoll) {
      const picked = selectedIds[0] || '';
      if (picked === 'reject') {
        reactionType = 'rejected';
        body = 'User rejected ' + approvalIssueId + ' via approval poll. Do NOT execute. Stop and wait for the operator\u2019s next instruction.';
      } else if (picked === 'investigate') {
        reactionType = 'other';
        body = 'User selected "Investigate further" for ' + approvalIssueId + ' via approval poll. Produce a deeper RCA with explicit evidence; do NOT take action yet.';
      } else {
        reactionType = 'approved';
        body = 'User approved ' + approvalIssueId + ' via approval poll. Execute the proposed plan now.';
      }
    } else if (isOther) {
      body = 'User selected: Other \u2014 waiting for text reply';
      reactionType = 'other';
    } else {
      const allOpts = cachedPoll.answers.map(a => '- ' + a.body).join('\n');
      body = 'POLL RESPONSE: The operator selected their preferred plan.\n\n'
        + 'Question: ' + cachedPoll.question + '\n'
        + 'Options presented:\n' + allOpts + '\n\n'
        + 'SELECTED: ' + selectedOptions.join(', ') + '\n\n'
        + 'Execute the selected plan now. Do NOT re-investigate or propose alternatives.';
      reactionType = 'approved';
    }

    allUserMessages.push({
      type: 'poll.response',
      sender: e.sender,
      origin_server_ts: e.origin_server_ts,
      content: { body, msgtype: 'm.text' },
      _roomId: roomId,
      _isReaction: true,
      _reactionType: reactionType
    });
  }
}

if (allUserMessages.length === 0) {
  return [{ json: { hasMessages: false, messages: [], messageText: '', sourceRoom: DEFAULT_ROOM, mentionsClaude: false, mentionsOpenclaw: false } }];
}

allUserMessages.sort((a, b) => (a.origin_server_ts || 0) - (b.origin_server_ts || 0));
staticData.lastProcessedTimestamp = Math.max(...allUserMessages.map(e => e.origin_server_ts || 0));

sourceRoom = allUserMessages[allUserMessages.length - 1]._roomId;
const sourceSender = allUserMessages[allUserMessages.length - 1].sender;

const latestMsg = allUserMessages[allUserMessages.length - 1];
const body = latestMsg.content?.body || '';
const formattedBody = latestMsg.content?.formatted_body || '';
const hasReaction = allUserMessages.some(m => m._isReaction);

const mentionsClaude = hasReaction
  || body.includes('@claude:matrix.example.net')
  || body.includes('@claude')
  || formattedBody.includes('@claude:matrix.example.net');
const mentionsOpenclaw = body.includes('@openclaw:matrix.example.net')
  || body.includes('@openclaw')
  || formattedBody.includes('@openclaw:matrix.example.net');

const messageText = allUserMessages.map(e => e.content.body).join('\n');


// Record reaction feedback to SQLite (Pattern 9 \u2014 Learning & Adaptation)
if (allUserMessages.some(m => m._isReaction)) {
  for (const msg of allUserMessages.filter(m => m._isReaction)) {
    const feedbackType = msg._reactionType === 'approved' ? 'thumbs_up' : 'thumbs_down';
    const issueMatch = (msg.content?.body || '').match(/\[([A-Z0-9]+-\d+)\]/);
    const feedbackIssueId = issueMatch ? issueMatch[1] : '';
    const snippet = (msg.content?.body || '').substring(0, 200).replace(/'/g, "''");
    if (feedbackIssueId) {
      // Will be recorded via SSH in the session resume path
      msg._feedbackIssueId = feedbackIssueId;
      msg._feedbackType = feedbackType;
      msg._feedbackSnippet = snippet;
    }
  }
}



// Apply input sanitization to all user messages
for (const msg of allUserMessages) {
  if (msg.content?.body && !msg._isReaction && !msg._isReview) {
    const { clean, injectionDetected } = sanitizeInput(msg.content.body);
    if (injectionDetected) {
      msg.content.body = clean;
      msg._injectionDetected = true;
      // Log injection attempt
      console.warn('Prompt injection pattern detected from ' + msg.sender + ': ' + msg.content.body.substring(0, 100));
    }
  }
}

// Parse REVIEW_JSON from OpenClaw review responses (NL-A2A/v1)
for (const msg of allUserMessages) {
  if (!msg._isReaction && msg.content?.body) {
    const body = msg.content.body;
    const reviewMatch = body.match(/REVIEW_JSON:\s*({[^}]+})/);
    if (reviewMatch) {
      try {
        const review = JSON.parse(reviewMatch[1]);
        msg._isReview = true;
        msg._reviewVerdict = review.verdict || '';
        msg._reviewConfidence = review.confidence || -1;
        msg._reviewReason = review.reason || '';
        msg._reviewIssueId = review.issueId || '';

        // Log to a2a_task_log (will be done via SSH in the resume path)
        msg._a2aMessageType = 'review';
        msg._a2aPayload = JSON.stringify(review);

        // Determine automated action based on verdict
        if (review.verdict === 'AGREE' && review.confidence >= 0.7) {
          // High-confidence AGREE: auto-approve \u2014 rewrite message as approval
          msg.content.body = 'REVIEW AGREE (auto-approved, confidence ' + review.confidence + '): ' + review.reason + '\n\nUser approved: Proceed with the proposed plan.';
          msg._reactionType = 'approved';
          msg._autoApproved = true;
        } else if (review.verdict === 'DISAGREE') {
          // DISAGREE: rewrite as rejection + pause signal
          msg.content.body = 'REVIEW DISAGREE: ' + review.reason + '\n\nUser rejected: Analysis disputed by Tier 1 review. Operator review required.';
          msg._reactionType = 'rejected';
          msg._shouldPauseOnDisagree = true;
        } else if (review.verdict === 'AUGMENT') {
          // AUGMENT: add context and continue
          msg.content.body = 'REVIEW AUGMENT: ' + review.reason + '\n\nAdditional context from Tier 1 review. Incorporate this and continue.';
        }
        // Low-confidence AGREE: pass through as-is, let human decide
      } catch(e) {
        // Malformed JSON \u2014 pass through as regular message
      }
    }
  }
}

// Collect feedback entries for session_feedback DB write
const feedbackEntries = [];
for (const msg of allUserMessages.filter(m => m._isReaction && m._feedbackIssueId)) {
  feedbackEntries.push({
    issueId: msg._feedbackIssueId,
    feedbackType: msg._feedbackType,
    snippet: msg._feedbackSnippet || ''
  });
}

return [{ json: {
  hasMessages: true,
  sourceSender,
  messages: allUserMessages.map(e => ({
    sender: e.sender,
    body: e.content.body,
    ts: e.origin_server_ts,
    room: e._roomId,
    isReaction: !!e._isReaction,
    reactionType: e._reactionType || ''
  })),
  messageText,
  sourceRoom,
  mentionsClaude,
  mentionsOpenclaw,
  feedbackEntries
} }];

let messageText = $input.first().json.messageText || '';
const TEACHER_DM_ROOMS = (() => {
  // IFRNLLEI01PRD-653 multi-operator. Read the dynamic DM list
  // from the Fetch Operator DMs SSH step.
  try {
    const out = ($('Fetch Operator DMs').first().json.stdout || '')
      .split('\n').map(s => s.trim()).filter(s => s);
    return new Set(out);
  } catch (e) {
    return new Set();
  }
})();
const sourceRoom = $input.first().json.sourceRoom || '';
const mentionsClaude = $input.first().json.mentionsClaude || false;
const mentionsOpenclaw = $input.first().json.mentionsOpenclaw || false;

// Strip @claude mention from start of message
messageText = messageText.replace(/^@claude:matrix\.example\.net\s*/i, '').replace(/^@claude\s*/i, '').trim();

const trimmed = messageText.trim();
const lower = trimmed.toLowerCase();
const base64Message = Buffer.from(messageText).toString('base64');

// Check for PREFIX: message format (uppercase issue ID like CUBEOS-4, IFRNLLEI01PRD-41)
const prefixMatch = trimmed.match(/^([A-Z0-9]+-\d+):\s*([\s\S]*)$/);
if (prefixMatch) {
  const prefix = prefixMatch[1];
  const strippedText = prefixMatch[2].trim();
  if (!strippedText) {
    const body = 'Message body is empty. Usage: ' + prefix + ': <your message>';
    const matrixBody = JSON.stringify({ msgtype: 'm.notice', body });
    return [{ json: { command: 'empty', sub: '', args: [], messageText: '', base64Message: '', prefix, matrixBody, mentionsClaude, mentionsOpenclaw } }];
  }
  const base64Stripped = Buffer.from(strippedText).toString('base64');
  return [{ json: { command: 'message', sub: '', args: [], messageText: strippedText, base64Message: base64Stripped, prefix, originalText: messageText, mentionsClaude, mentionsOpenclaw } }];
}

// Teacher-DM free-text replies auto-grade the latest open quiz
// (IFRNLLEI01PRD-653 UX fix). Operator says '10' in their DM,
// bridge synthesizes `!grade 0 10` so cmd_grade looks up the
// latest completed_at=NULL quiz row.
if (!lower.startsWith('!') && trimmed && TEACHER_DM_ROOMS.has(sourceRoom)) {
  return [{ json: { command: 'teacher', sub: '', args: [trimmed],
    messageText: trimmed, base64Message,
    legacyCommand: 'grade', prefix: '',
    mentionsClaude, mentionsOpenclaw } }];
}

// Not a command
if (!lower.startsWith('!')) {
  if (!trimmed) {
    return [{ json: { command: 'empty', sub: '', args: [], messageText: '', base64Message: '', prefix: '', matrixBody: JSON.stringify({ msgtype: 'm.notice', body: 'Message cannot be empty.' }), mentionsClaude, mentionsOpenclaw } }];
  }
  return [{ json: { command: 'message', sub: '', args: [], messageText, base64Message, prefix: '', mentionsClaude, mentionsOpenclaw } }];
}

// Use lowercase for command routing, original case for args
const lowerParts = lower.slice(1).split(/\s+/);
const origParts = trimmed.slice(1).split(/\s+/);
const command = lowerParts[0] || '';
const sub = lowerParts[1] || '';
const args = origParts.slice(2);

// Legacy aliases
const resolved = command === 'done' ? 'session'
  : command === 'cancel' ? 'session'
  : command === 'status' ? 'session'
  : command === 'offline' ? 'gateway'
  : command === 'online' ? 'gateway'
  : command;

const resolvedSub = command === 'done' ? 'done'
  : command === 'cancel' ? 'cancel'
  : command === 'status' ? 'current'
  : command === 'offline' ? 'offline'
  : command === 'online' ? 'online'
  : sub;

// Teacher-agent commands (IFRNLLEI01PRD-653).
// Route !learn / !quiz / !progress / !digest / !leaderboard / !skip / !teach /
// !grade through a single 'teacher' command; the teacher-runner workflow's
// Parse Command node dispatches based on legacyCommand + sub + args.
const TEACHER_CMDS = new Set(['learn', 'quiz', 'progress', 'digest', 'leaderboard', 'skip', 'teach', 'grade']);
if (TEACHER_CMDS.has(command)) {
  return [{ json: { command: 'teacher', sub, args, messageText, base64Message, legacyCommand: command, prefix: '', mentionsClaude, mentionsOpenclaw } }];
}

return [{ json: { command: resolved, sub: resolvedSub, args, messageText, base64Message, legacyCommand: command, prefix: '', mentionsClaude, mentionsOpenclaw } }];

const sessionStdout = $('Read Session File').first().json.stdout || '{}';
const queueStdout = $('Read and Clear Queue').first().json.stdout || '';
const currentMessage = $('Detect Command').first().json.messageText;
const base64Current = $('Detect Command').first().json.base64Message;
const prefix = $('Detect Command').first().json.prefix || '';

let session;
try {
  session = JSON.parse(sessionStdout.trim());
} catch (e) {
  session = { sessionId: '', issueId: '', paused: 0, issue_title: '', lastResponseB64: '' };
}

const isPaused = !!session.paused;
const hasSession = !!session.sessionId && !isPaused;
const isRouted = !!prefix && hasSession;

// If paused, queue stdout will be 'PAUSED' — don't decode
let queuedMessages = [];
if (queueStdout.trim() && queueStdout.trim() !== 'PAUSED') {
  queuedMessages = queueStdout.trim().split('\n')
    .map(line => {
      try { return Buffer.from(line.trim(), 'base64').toString('utf8'); }
      catch(e) { return ''; }
    })
    .filter(m => m);
}

// Build context summary for session resume
let contextSummary = '';
if (hasSession) {
  const issueId = session.issueId || '';
  const title = session.issue_title || session.issueTitle || '';
  const sessionPrefix = issueId.split('-')[0] || '';

  contextSummary = '[Session context] Resuming session for ' + issueId;
  if (title) contextSummary += ': ' + title;
  contextSummary += '.\n';

  // Add project context
  if (sessionPrefix === 'IFRNLLEI01PRD') {
    contextSummary += 'Project: Infrastructure NLLEI01 (IaC repo). Remember: all changes require human approval.\n';
  } else if (sessionPrefix === 'IFRGRSKG01PRD') {
    contextSummary += 'Project: Infrastructure GRSKG01 (GR site). Remember: all changes require human approval.\n';
  } else if (sessionPrefix === 'MESHSAT') {
    contextSummary += 'Project: MeshSat/CubeOS. Push directly to main.\n';
  } else if (sessionPrefix === 'CUBEOS') {
    contextSummary += 'Project: CubeOS.\n';
  }

  // If there were queued messages, note the gap
  if (queuedMessages.length > 0) {
    contextSummary += 'Note: ' + queuedMessages.length + ' message(s) were queued while you were busy. Process them in order.\n';
  }

  // Inject last response for context window continuity
  const lastResponseB64 = session.lastResponseB64 || '';
  if (lastResponseB64) {
    try {
      const lastResponse = Buffer.from(lastResponseB64, 'base64').toString('utf8');
      if (lastResponse) {
        const truncResp = lastResponse.length > 600
          ? lastResponse.substring(0, 600) + '\n[...truncated]'
          : lastResponse;
        contextSummary += '\nYour last response (for context continuity):\n' + truncResp + '\n';
      }
    } catch(e) {}
  }

  contextSummary += '\n';
}

// Combine: context summary + queued messages + current message
let fullMessage = '';
if (queuedMessages.length > 0) {
  fullMessage = contextSummary + 'Previously queued messages:\n' + queuedMessages.join('\n') + '\n\nLatest message:\n' + currentMessage;
} else {
  fullMessage = contextSummary + currentMessage;
}

const base64Message = Buffer.from(fullMessage).toString('base64');

return [{ json: {
  sessionId: session.sessionId || '',
  issueId: session.issueId || '',
  hasSession,
  isPaused,
  isRouted,
  prefix,
  messageText: fullMessage,
  base64Message,
  base64Current,
  queuedCount: queuedMessages.length
} }];

const stdout = $input.first().json.stdout || '';
const stderr = $input.first().json.stderr || '';
const issueId = $('Build Context').first().json.issueId;
const queuedCount = $('Build Context').first().json.queuedCount || 0;

const output = stdout.trim() || stderr.trim();

let result;
let sessionExpired = false;

if (!output) {
  result = 'No response from Claude (empty output). The session is still active \u2014 try sending your message again.';
} else {
  try {
    const parsed = JSON.parse(output);
    result = parsed.result || '';
    if (!result && parsed.is_error) {
      result = 'Claude error: ' + (parsed.result || 'unknown error');
    }
    if (parsed.is_error) {
      const errText = (parsed.error || parsed.result || '').toLowerCase();
      if (errText.includes('session') && (errText.includes('not found') || errText.includes('invalid') || errText.includes('expired'))) {
        sessionExpired = true;
      }
    }
    if (!result) {
      result = 'Claude returned an empty result. The session is still active \u2014 try again or end with !done.';
    }
  } catch (e) {
    result = output.substring(0, 1000);
  }
}

if (queuedCount > 0) {
  result = '(included ' + queuedCount + ' queued message' + (queuedCount > 1 ? 's' : '') + ')\n\n' + result;
}

if (sessionExpired) {
  result += '\n\n_Session has expired. Cleaning up \u2014 start a new session via YouTrack._';
}

return [{ json: { result, issueId, sessionExpired } }];

function applyInline(text) {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/\*(.+?)\*/g, '<em>$1</em>')
    .replace(/(?<!\w)_([^_]+)_(?!\w)/g, '<em>$1</em>')
    .replace(/~~(.+?)~~/g, '<del>$1</del>')
    .replace(/`([^`]+)`/g, '<code>$1</code>')
    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');
}

function markdownToHtml(md) {
  if (!md) return '';
  const lines = md.split('\n');
  const outputLines = [];
  let i = 0;
  while (i < lines.length) {
    const line = lines[i];
    if (line.trimStart().startsWith('```')) {
      const codeLines = [line]; i++;
      while (i < lines.length && !lines[i].trimStart().startsWith('```')) { codeLines.push(lines[i]); i++; }
      if (i < lines.length) { codeLines.push(lines[i]); i++; }
      const content = codeLines.slice(1, -1).join('\n');
      const escaped = content.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
      outputLines.push('<pre><code>' + escaped + '</code></pre>'); continue;
    }
    if (/^\|.+\|$/.test(line.trim())) {
      const tableLines = [];
      while (i < lines.length && /^\|.+\|$/.test(lines[i].trim())) { tableLines.push(lines[i].trim()); i++; }
      const rows = tableLines.filter(l => !/^\|[\s|:-]+\|$/.test(l));
      if (rows.length === 0) continue;
      const parseRow = (row) => row.split('|').slice(1, -1).map(c => c.trim());
      const headerCells = parseRow(rows[0]); const dataRows = rows.slice(1);
      const thead = '<thead><tr>' + headerCells.map(c => '<th>' + applyInline(c) + '</th>').join('') + '</tr></thead>';
      const tbody = dataRows.length > 0 ? '<tbody>' + dataRows.map(row => '<tr>' + parseRow(row).map(c => '<td>' + applyInline(c) + '</td>').join('') + '</tr>').join('') + '</tbody>' : '';
      outputLines.push('<table>' + thead + tbody + '</table>'); continue;
    }
    if (/^>\s?/.test(line)) {
      const bq = []; while (i < lines.length && /^>\s?/.test(lines[i])) { bq.push(lines[i].replace(/^>\s?/,'')); i++; }
      outputLines.push('<blockquote>' + bq.map(x => applyInline(x)).join('<br>') + '</blockquote>'); continue;
    }
    if (/^(\s*)[-*+] /.test(line)) {
      const parseList = (indent) => {
        const lis = [];
        while (i < lines.length) {
          const m = lines[i].match(/^(\s*)[-*+] (.*)$/);
          if (!m) break;
          const depth = m[1].length;
          if (depth < indent) break;
          if (depth === indent) { lis.push(applyInline(m[2])); i++; }
          else { const sub = parseList(depth); lis[lis.length - 1] += '<ul>' + sub.map(x => '<li>' + x + '</li>').join('') + '</ul>'; }
        }
        return lis;
      };
      const indent = (line.match(/^(\s*)/) || ['',''])[1].length;
      const lis = parseList(indent);
      outputLines.push('<ul>' + lis.map(x => '<li>' + x + '</li>').join('') + '</ul>'); continue;
    }
    if (/^\d+\. /.test(line)) {
      const listItems = [];
      while (i < lines.length && /^\d+\. /.test(lines[i])) { listItems.push(lines[i].replace(/^\d+\. /, '')); i++; }
      outputLines.push('<ol>' + listItems.map(item => '<li>' + applyInline(item) + '</li>').join('') + '</ol>'); continue;
    }
    const h3 = line.match(/^### (.+)$/); if (h3) { outputLines.push('<h3>' + applyInline(h3[1]) + '</h3>'); i++; continue; }
    const h2 = line.match(/^## (.+)$/); if (h2) { outputLines.push('<h2>' + applyInline(h2[1]) + '</h2>'); i++; continue; }
    const h1 = line.match(/^# (.+)$/); if (h1) { outputLines.push('<h1>' + applyInline(h1[1]) + '</h1>'); i++; continue; }
    if (/^---+$/.test(line.trim())) { outputLines.push('<hr>'); i++; continue; }
    outputLines.push(applyInline(line)); i++;
  }
  const blockTags = /^<(h[1-6]|ul|ol|pre|table|hr|blockquote)/;
  const parts = [];
  let textBuf = [];
  for (const item of outputLines) {
    if (blockTags.test(item)) {
      if (textBuf.length > 0) { parts.push('<p>' + textBuf.join('<br>') + '</p>'); textBuf = []; }
      parts.push(item);
    } else if (item === '') {
      if (textBuf.length > 0) { parts.push('<p>' + textBuf.join('<br>') + '</p>'); textBuf = []; }
    } else {
      textBuf.push(item);
    }
  }
  if (textBuf.length > 0) parts.push('<p>' + textBuf.join('<br>') + '</p>');
  return parts.join('');
}

function parsePoll(result) {
  // Anchor [POLL] to start-of-line and prefer the LAST occurrence so a
  // mid-sentence "[POLL]" inside Claude's prose (e.g. quoting prompt
  // instructions back at us) cannot hijack the parse. Bug 1, see
  // IFRNLLEI01PRD-734 / -723.
  const pollLineRe = /^\[POLL\]\s*(.+?)\s*$/gm;
  const matches = [...result.matchAll(pollLineRe)];
  let pollMatch = matches.length ? matches[matches.length - 1] : null;
  if (!pollMatch) return null;
  const question = pollMatch[1].trim();
  // Sweep options block AFTER the [POLL] line. Stop at any line that's
  // clearly not a plan option, so trailing prose like
  // "Awaiting approval to proceed" or "Then file a follow-up task..." or
  // "My recommendation is Plan A" can't be absorbed as a fake option.
  // Bug 2, see IFRNLLEI01PRD-731/-706/-728/-732/-620 etc.
  const STOP_RE = /^(?:CONFIDENCE:|\[AUTO-RESOLVE|#{1,6}\s|`{3,}|~{3,}|-{3,}\s*$|={3,}\s*$|Awaiting\s+approval\b|Reply\s+["']?approved\b|My\s+recommendation\b|Then\s+file\b|Note:|Notes?\s*:|Caveat:|Also[, ])/i;
  const startIdx = pollMatch.index + pollMatch[0].length;
  const tailLines = result.slice(startIdx).split('\n');
  const optLines = [];
  // Skip blank lines (don't treat them as block terminators) — Markdown
  // poll bodies often separate options with a blank line for emphasis,
  // e.g. MESHSAT-664. A line is only a stop signal if STOP_RE matches it
  // after bullet/number stripping.
  //
  // Track the FIRST option's indentation as the "top level" — lines that
  // are indented more than that are sub-bullets describing a parent
  // option, so they should be skipped (not absorbed as fake options).
  // Bug 7, see MESHSAT-623 where Plan A had 4 indented sub-bullets each
  // and the parser was producing 10 options instead of 2.
  let blankRun = 0;
  let topIndent = -1;
  for (const raw of tailLines) {
    const line = raw.trim();
    if (!line) { blankRun++; if (blankRun >= 3) break; continue; }
    blankRun = 0;
    const cleaned = line.replace(/^[-*+]\s+/, '').replace(/^\d+[.)]\s+/, '').trim();
    if (!cleaned) continue;
    if (STOP_RE.test(cleaned)) break;
    const indent = raw.length - raw.replace(/^\s+/, '').length;
    if (topIndent < 0) topIndent = indent;
    if (indent > topIndent) continue; // sub-bullet of a parent option — skip
    optLines.push(cleaned);
  }
  if (optLines.length < 2) return null;
  const answers = optLines.map((opt, i) => ({ id: 'opt' + i, 'org.matrix.msc3381.text.body': opt }));
  const context = result.slice(0, pollMatch.index).trim();
  return { question, answers, context };
}

const data = $('Parse Response').first().json;
const issueId = data.issueId || '';
const result = data.result || 'No response';
const isRouted = $('Build Context').first().json.isRouted || false;

let routingPrefix = '';
let htmlRouting = '';
if (isRouted) {
  routingPrefix = '\u2192 Routed to ' + issueId + '\n\n';
  htmlRouting = '<p><em>\u2192 Routed to ' + issueId + '</em></p>';
}

// IFRNLLEI01PRD-632: check [AUTO-RESOLVE] first — low-risk sessions marked by
// Classify Risk + Build Prompt end with this marker and get posted as m.notice
// (no ping). Mutually exclusive with [POLL]; the prompt tells Claude to use
// one or the other, never both.
let matrixBody;
let matrixEventType = 'm.room.message';

if (/\[AUTO-RESOLVE\]/.test(result)) {
  const cleaned = result.replace(/\s*\[AUTO-RESOLVE\][\s\S]*$/, '').trim();
  const plainText = routingPrefix + '[' + issueId + '] Claude (auto-resolved):\n\n' + cleaned.substring(0, 4000);
  const htmlText = htmlRouting + '<p><strong>[' + issueId + '] Claude <em>(auto-resolved)</em>:</strong></p>' + markdownToHtml(cleaned.substring(0, 4000));
  matrixBody = JSON.stringify({
    msgtype: 'm.notice',  // no ping, appears dimmer in most clients
    body: plainText,
    format: 'org.matrix.custom.html',
    formatted_body: htmlText
  });
  return [{ json: { issueId, result, matrixBody, matrixEventType: 'm.room.message', contextBody: '', autoResolved: true } }];
}

// Check for [POLL] in response
const poll = parsePoll(result);

if (poll) {
  const contextPlain = poll.context ? routingPrefix + '[' + issueId + '] Claude:\n\n' + poll.context.substring(0, 4000) : '';
  const contextHtml = poll.context ? htmlRouting + '<p><strong>[' + issueId + '] Claude:</strong></p>' + markdownToHtml(poll.context.substring(0, 4000)) : '';

  const fallbackText = poll.question + '\n' + poll.answers.map((a, i) => (i+1) + '. ' + a['org.matrix.msc3381.text.body']).join('\n');
  matrixBody = JSON.stringify({
    'org.matrix.msc3381.poll.start': {
      kind: 'org.matrix.msc3381.poll.disclosed',
      max_selections: 1,
      question: { body: '[' + issueId + '] ' + poll.question, msgtype: 'm.text' },
      answers: poll.answers
    },
    body: fallbackText,
    msgtype: 'm.text'
  });
  matrixEventType = 'org.matrix.msc3381.poll.start';

  return [{ json: { issueId, result, matrixBody, matrixEventType, contextBody: contextPlain ? JSON.stringify({ msgtype: 'm.text', body: contextPlain, format: 'org.matrix.custom.html', formatted_body: contextHtml }) : '' } }];
}

// Regular (non-poll) response
const needsApproval = /approv|waiting|human|confirm/i.test(result);
const mentionPill = needsApproval ? '<a href="https://matrix.to/#/@dominicus:matrix.example.net">@dominicus</a> ' : '';
const mentionPlain = needsApproval ? '@dominicus ' : '';

const plainText = mentionPlain + routingPrefix + '[' + issueId + '] Claude:\n\n' + result.substring(0, 4000);
const htmlText = mentionPill + htmlRouting + '<p><strong>[' + issueId + '] Claude:</strong></p>' + markdownToHtml(result.substring(0, 4000));

matrixBody = JSON.stringify({
  msgtype: 'm.text',
  body: plainText,
  format: 'org.matrix.custom.html',
  formatted_body: htmlText
});

return [{ json: { issueId, result, matrixBody, matrixEventType: 'm.room.message', contextBody: '' } }];

const stdout = $input.first().json.stdout || '';
const stderr = $input.first().json.stderr || '';
const sub = $('Detect Command').first().json.sub || 'current';
const output = (stdout.trim() || stderr.trim());

let body = '';

if (sub === 'current') {
  const parts = {};
  output.split('|').forEach(p => {
    const [k, ...v] = p.split(':');
    parts[k] = v.join(':');
  });
  const sessionRaw = (parts.SESSION || '').trim();
  const queueCount = parts.QUEUE || '0';
  const other = parseInt(parts.OTHER || '0');
  const load = parts.LOAD || '?';
  const mem = parts.MEM || '?';
  const procs = parts.PROCS || '0';
  const lock = parts.LOCK || '?';

  if (!sessionRaw || sessionRaw === 'NO_SESSION') {
    body = 'No active session. Move an issue to In Progress in YouTrack to start a new session.';
  } else {
    try {
      const s = JSON.parse(sessionRaw);
      const started = new Date(s.started_at + 'Z');
      const mins = Math.floor((Date.now() - started.getTime()) / 60000);
      const h = Math.floor(mins / 60);
      const m = mins % 60;
      const duration = h > 0 ? h + 'h ' + m + 'm' : m + 'm';
      body = 'Current session:\n'
        + 'Issue    : ' + s.issue_id + '\n'
        + 'Title    : ' + (s.issue_title || '\u2014') + '\n'
        + 'Started  : ' + s.started_at + '\n'
        + 'Duration : ' + duration + '\n'
        + 'Messages : ' + s.message_count + '\n'
        + 'Paused   : ' + (s.paused ? 'Yes' : 'No') + '\n'
        + 'Queue    : ' + queueCount + ' pending';
    } catch(e) { body = 'Error parsing session: ' + sessionRaw.substring(0,200); }
  }
  body += '\n\nSystem:\n'
    + 'Load     : ' + load + '\n'
    + 'Memory   : ' + mem + '\n'
    + 'Claude   : ' + procs + ' process(es)\n'
    + 'Slots    : ' + lock;

  if (other > 0) {
    body += '\n\nOther active sessions: ' + other + '. Type !session list to see all.';
  }

} else if (sub === 'list') {
  let sessionsJson = output || '[]';
  let locksStr = '';
  if (output.startsWith('SESSIONS:')) {
    const pipeIdx = output.indexOf('|LOCKS:');
    sessionsJson = output.substring(9, pipeIdx > 0 ? pipeIdx : undefined);
    if (pipeIdx > 0) locksStr = output.substring(pipeIdx + 7);
  }
  try {
    const rows = JSON.parse(sessionsJson);
    if (!rows.length) { body = 'No active sessions.'; }
    else {
      const lines = rows.map((s, i) => {
        const started = new Date(s.started_at + 'Z');
        const mins = Math.floor((Date.now() - started.getTime()) / 60000);
        const h = Math.floor(mins / 60);
        const m = mins % 60;
        const dur = h > 0 ? h + 'h ' + m + 'm' : m + 'm';
        return (i+1) + '  ' + s.issue_id.padEnd(20) + (s.issue_title||'').substring(0,25).padEnd(26) + dur.padEnd(10) + (s.is_current ? ' \u2713' : '');
      });
      body = 'Active sessions (' + rows.length + '):\n'
        + '#  Issue               Title                    Duration  Current\n'
        + lines.join('\n');
    }
    if (locksStr) {
      body += '\n\nSlot locks:\n';
      locksStr.split(',').forEach(l => {
        const eq = l.indexOf('=');
        const slot = l.substring(0, eq);
        const val = l.substring(eq + 1);
        body += '  ' + slot.padEnd(12) + (val === 'free' ? 'free' : val + ' (locked)') + '\n';
      });
    }
  } catch(e) { body = 'Error: ' + output.substring(0,200); }

} else if (sub === 'done') {
  if (!output || output.trim() === '') {
    body = 'No active session to end.';
  } else {
    try {
      const s = JSON.parse(output);
      if (!s.session_id) { body = 'No active session to end.'; }
      else { body = 'TRIGGER_DONE:' + JSON.stringify({sessionId: s.session_id, issueId: s.issue_id, issueTitle: s.issue_title}); }
    } catch(e) { body = 'No active session to end.'; }
  }

} else if (sub === 'cancel') {
  if (output.startsWith('CANCELLED:')) body = 'Session ' + output.split(':')[1] + ' cancelled. Lock cleared, queue emptied.';
  else if (output === 'NO_SESSION') body = 'No active session to cancel.';
  else body = output;

} else if (sub === 'pause') {
  if (output.startsWith('PAUSED:')) body = 'Session ' + output.split(':')[1] + ' paused. Messages will be queued but not delivered.\nType !session resume to unpause.';
  else if (output === 'NO_SESSION') body = 'No active session to pause.';
  else body = output;

} else if (sub === 'resume') {
  if (output.startsWith('RESUMED:')) {
    const parts = {};
    output.split('~').forEach(p => { const [k,...v] = p.split(':'); parts[k] = v.join(':'); });
    const issueId = parts.RESUMED || '?';
    const sessionId = parts.SID || '';
    const queueCount = parseInt(parts.QC || '0');
    body = 'Session ' + issueId + ' resumed.';
    if (queueCount > 0) body += ' Draining ' + queueCount + ' queued message(s)...';
    const matrixBody = JSON.stringify({ msgtype: 'm.notice', body });
    return [{ json: { matrixBody, isDone: false, triggerData: null, isResume: true, drainSessionId: sessionId, drainIssueId: issueId, drainQueueCount: queueCount } }];
  }
  else if (output === 'NO_SESSION') body = 'No active session to resume.';
  else body = output;

} else if (sub === 'switch') {
  if (output === 'USAGE') body = 'Usage: !session switch <issue-id>';
  else if (output.startsWith('SWITCHED:')) body = 'Current session switched to ' + output.split(':')[1] + '.\nMessages will now be routed to this session.';
  else if (output.startsWith('NOT_FOUND:')) body = 'No active session for ' + output.split(':')[1] + '.';
  else body = output;

} else if (sub === 'log') {
  body = output || 'No log available.';

} else {
  body = 'Unknown session command: ' + sub + '\n\n' +
    '!session commands:\n' +
    'current              \u2014 Show current active session details\n' +
    'list                 \u2014 List all active sessions\n' +
    'done [issue-id]      \u2014 End session \u2192 YouTrack To Verify\n' +
    'cancel [issue-id]    \u2014 Hard abort session, clear lock + queue\n' +
    'pause [issue-id]     \u2014 Hold queue, stop processing messages\n' +
    'resume [issue-id]    \u2014 Resume paused session\n' +
    'switch <issue-id>    \u2014 Change current session\n' +
    'log [issue-id]       \u2014 Last 50 lines of execution log\n' +
    '\n' +
    '[issue-id] is optional \u2014 defaults to current session if omitted.';
}

const isDone = body.startsWith('TRIGGER_DONE:');
let triggerData = null;
if (isDone) {
  try { triggerData = JSON.parse(body.replace('TRIGGER_DONE:', '')); } catch(e) {}
  body = 'Ending session for ' + (triggerData?.issueId || '?') + '...';
}

const matrixBody = JSON.stringify({ msgtype: 'm.notice', body });

return [{ json: { matrixBody, isDone, triggerData } }];

if ($json.matrixBody) {
  return [{ json: { matrixBody: $json.matrixBody, isDone: false, triggerData: null } }];
}
const command = $json.command || 'unknown';
const body = 'Unknown command: !' + command + '\n\n' +
    'Available commands:\n' +
    '!session    \u2014 Manage active Claude sessions\n' +
    '!issue      \u2014 Manage YouTrack issues\n' +
    '!pipeline   \u2014 Monitor GitLab CI pipelines\n' +
    '!system     \u2014 View system status\n' +
    '!gateway    \u2014 Switch between online/offline mode\n' +
    '!mode       \u2014 Switch gateway routing mode\n' +
    '!debug      \u2014 Dump raw gateway state\n' +
    '!help <cmd> \u2014 Show subcommands for a command\n' +
    '\n' +
    'Legacy shortcuts: !done, !status, !cancel\n' +
    'Mode shortcuts: !offline, !online';
const matrixBody = JSON.stringify({ msgtype: 'm.notice', body });
return [{ json: { matrixBody, isDone: false, triggerData: null } }];

