parameters.jsCode:
const stdout = $input.first().json.stdout || '';
const stderr = $input.first().json.stderr || '';
const sub = $('Detect Command').first().json.sub || '';
const args = $('Detect Command').first().json.args || [];
const arg0 = (args[0] || '').toUpperCase();
const output = (stdout.trim() || stderr.trim());

let body = '';

let httpStatus = 0;
let responseBody = output;
const statusMatch = output.match(/\nHTTP_STATUS:(\d+)$/);
if (statusMatch) {
  httpStatus = parseInt(statusMatch[1]);
  responseBody = output.replace(/\nHTTP_STATUS:\d+$/, '').trim();
}

// Check for session info appended by Handle Issue (done/close/toverify/verify)
let sessionData = null;
const sessionMatch = output.match(/HAS_SESSION:(.+)/);
if (sessionMatch) {
  try { sessionData = JSON.parse(sessionMatch[1]); } catch(e) {}
  responseBody = responseBody.replace(/\n?HAS_SESSION:.+/, '').trim();
}

// Check for session cleanup (open command)
let sessionCleaned = false;
const cleanMatch = output.match(/SESSION_CLEANED:(.+)/);
if (cleanMatch) {
  sessionCleaned = true;
  responseBody = responseBody.replace(/\n?SESSION_CLEANED:.+/, '').trim();
}

function getField(customFields, fieldName) {
  const cf = (customFields || []).find(f => f.name === fieldName);
  if (!cf || cf.value === null || cf.value === undefined) return null;
  if (typeof cf.value === 'object') return cf.value.name || cf.value.login || null;
  return String(cf.value);
}

if (output.startsWith('USAGE') || !sub) {
  body = '!issue subcommands:\n'
    + 'status              \u2014 List In Progress + Open issues\n'
    + 'info <id>           \u2014 Show issue details\n'
    + 'open <id>           \u2014 Move to Open (ends session)\n'
    + 'inprogress <id>     \u2014 Move to In Progress (starts session)\n'
    + 'start <id>          \u2014 Alias for inprogress\n'
    + 'toverify <id>       \u2014 Move to To Verify (ends session)\n'
    + 'verify <id>         \u2014 Alias for toverify\n'
    + 'done <id>           \u2014 Move to Done (ends session)\n'
    + 'close <id>          \u2014 Alias for done\n'
    + 'stop <id>           \u2014 Move back to Open (no session change)\n'
    + 'comment <id> <text> \u2014 Post comment to issue\n'
    + 'Example: !issue inprogress CUBEOS-21';

} else if (output.startsWith('INVALID_ID:')) {
  const id = output.split(':')[1] || 'none';
  body = 'Invalid issue ID: ' + id + '. Expected format: CUBEOS-4';

} else if (output.startsWith('LOOKUP_FAILED:')) {
  const id = output.split(':')[1] || '?';
  body = 'Failed to look up numeric ID for ' + id + '. Issue may not exist.';

} else if (output.startsWith('NO_TEXT')) {
  body = 'Usage: !issue comment <id> <text>';

} else if (output.startsWith('ACTIVE_SESSION:')) {
  const id = output.split(':')[1];
  body = 'Session is active for ' + id + '.\nUse !session done or !session cancel first.';

} else if (output.startsWith('START_SESSION:')) {
  const lines = output.split('\n');
  const issueId = lines[0].split(':')[1] || '';
  let b64Summary = '';
  let b64Desc = '';
  let b64Comments = '';
  let summary = '';
  for (const line of lines) {
    if (line.startsWith('B64_SUMMARY:')) {
      b64Summary = line.substring(12);
      try { summary = Buffer.from(b64Summary, 'base64').toString('utf8'); } catch(e) {}
    } else if (line.startsWith('B64_DESC:')) {
      b64Desc = line.substring(9);
    } else if (line.startsWith('B64_COMMENTS:')) {
      b64Comments = line.substring(13);
    }
  }
  body = issueId + ' moved to In Progress.\nStarting Claude session \u2014 this may take a few minutes...';
  const matrixBody = JSON.stringify({ msgtype: 'm.notice', body });
  return [{ json: { matrixBody, isDone: false, triggerData: null, isStartSession: true, issueId, summary, b64Summary, b64Desc, b64Comments } }];

} else if (output.startsWith('UNKNOWN_SUB:')) {
  body = 'Unknown issue command: ' + output.split(':')[1] + '\n\n' +
    '!issue commands:\n\n' +
    'State transitions:\n' +
    'open <id>           \u2014 Move to Open (ends active session)\n' +
    'inprogress <id>     \u2014 Move to In Progress (starts session)\n' +
    'toverify <id>       \u2014 Move to To Verify (ends session if active)\n' +
    'done <id>           \u2014 Move to Done (ends session if active)\n\n' +
    'Aliases:\n' +
    'start <id>          \u2014 Alias for inprogress\n' +
    'verify <id>         \u2014 Alias for toverify\n' +
    'close <id>          \u2014 Alias for done\n' +
    'stop <id>           \u2014 Move back to Open (no session change)\n\n' +
    'Other:\n' +
    'status              \u2014 List In Progress + Open issues\n' +
    'info <id>           \u2014 Show issue details\n' +
    'comment <id> <text> \u2014 Post comment to issue\n\n' +
    'Example: !issue inprogress CUBEOS-21';

} else if (httpStatus === 0 && !responseBody) {
  body = 'YouTrack request failed (no response). Try again.';

} else if (sub === 'status') {
  if (httpStatus >= 400) {
    body = 'YouTrack error (' + httpStatus + '). Try again.';
  } else {
    try {
      const issues = JSON.parse(responseBody);
      if (!issues.length) {
        body = 'No In Progress or Open issues in CUBEOS.';
      } else {
        const byState = {};
        issues.forEach(i => {
          const state = getField(i.customFields, 'State') || 'Unknown';
          if (!byState[state]) byState[state] = [];
          byState[state].push(i);
        });
        const lines = ['CUBEOS issues:'];
        for (const state of Object.keys(byState)) {
          const items = byState[state];
          lines.push('');
          lines.push(state + ' (' + items.length + '):');
          items.forEach(i => {
            lines.push('  ' + (i.idReadable || i.id) + '  ' + (i.summary || '').substring(0, 60));
          });
        }
        lines.push('');
        lines.push('Type !issue info <id> for details.');
        body = lines.join('\n');
      }
    } catch (e) {
      body = 'Error parsing YouTrack response: ' + responseBody.substring(0, 200);
    }
  }

} else if (sub === 'info') {
  if (httpStatus >= 400) {
    body = httpStatus === 404 ? 'Issue ' + arg0 + ' not found.' : 'YouTrack error (' + httpStatus + '). Try again.';
  } else {
    try {
      const issue = JSON.parse(responseBody);
      const state = getField(issue.customFields, 'State') || '\u2014';
      const priority = getField(issue.customFields, 'Priority') || '\u2014';
      const assignee = getField(issue.customFields, 'Assignee') || '\u2014';
      const updated = issue.updated ? new Date(issue.updated).toISOString().replace('T', ' ').substring(0, 16) : '\u2014';
      const tags = (issue.tags || []).map(t => t.name).join(', ') || '\u2014';
      const desc = (issue.description || '\u2014').substring(0, 300);
      body = (issue.idReadable || issue.id) + ' \u2014 ' + (issue.summary || '') + '\n'
        + 'State     : ' + state + '\n'
        + 'Priority  : ' + priority + '\n'
        + 'Assignee  : ' + assignee + '\n'
        + 'Updated   : ' + updated + '\n'
        + 'Tags      : ' + tags + '\n'
        + 'Description (first 300 chars):\n' + desc + '\n\n'
        + 'Link: https://youtrack.example.net/issue/' + (issue.idReadable || issue.id);
    } catch (e) {
      body = 'Error parsing YouTrack response: ' + responseBody.substring(0, 200);
    }
  }

} else if (sub === 'start' || sub === 'inprogress') {
  if (httpStatus >= 200 && httpStatus < 300) {
    body = arg0 + ' moved to In Progress.\nClaude session will start automatically via YouTrack webhook.';
  } else if (httpStatus === 0 && !output.includes('CURL_ERROR')) {
    body = arg0 + ' moved to In Progress.\nClaude session will start automatically via YouTrack webhook.';
  } else {
    body = 'Failed to update ' + arg0 + ' (HTTP ' + httpStatus + '): ' + responseBody.substring(0, 200);
  }

} else if (sub === 'open') {
  if (httpStatus >= 200 && httpStatus < 300) {
    body = arg0 + ' moved to Open.';
  } else if (httpStatus === 0 && !output.includes('CURL_ERROR')) {
    body = arg0 + ' moved to Open.';
  } else {
    body = 'Failed to update ' + arg0 + ' (HTTP ' + httpStatus + '): ' + responseBody.substring(0, 200);
  }
  if (sessionCleaned && body.includes('moved to Open')) {
    body += '\nActive session ended and cleaned up.';
  }

} else if (sub === 'stop') {
  if (httpStatus >= 200 && httpStatus < 300) {
    body = arg0 + ' moved back to Open.';
  } else if (httpStatus === 0 && !output.includes('CURL_ERROR')) {
    body = arg0 + ' moved back to Open.';
  } else {
    body = 'Failed to update ' + arg0 + ' (HTTP ' + httpStatus + '): ' + responseBody.substring(0, 200);
  }

} else if (sub === 'verify' || sub === 'toverify') {
  if (httpStatus >= 200 && httpStatus < 300) {
    body = arg0 + ' set to To Verify.';
  } else if (httpStatus === 0 && !output.includes('CURL_ERROR')) {
    body = arg0 + ' set to To Verify.';
  } else {
    body = 'Failed to update ' + arg0 + ' (HTTP ' + httpStatus + '): ' + responseBody.substring(0, 200);
  }
  if (sessionData && body.includes('To Verify')) {
    const matrixBody = JSON.stringify({ msgtype: 'm.notice', body });
    return [{ json: { matrixBody, isDone: true, triggerData: { sessionId: sessionData.sessionId, issueId: sessionData.issueId } } }];
  }

} else if (sub === 'done' || sub === 'close') {
  if (httpStatus >= 200 && httpStatus < 300) {
    body = arg0 + ' moved to Done.';
  } else if (httpStatus === 0 && !output.includes('CURL_ERROR')) {
    body = arg0 + ' moved to Done.';
  } else {
    body = 'Failed to update ' + arg0 + ' (HTTP ' + httpStatus + '): ' + responseBody.substring(0, 200);
  }
  if (sessionData && body.includes('moved to Done')) {
    const matrixBody = JSON.stringify({ msgtype: 'm.notice', body });
    return [{ json: { matrixBody, isDone: true, triggerData: { sessionId: sessionData.sessionId, issueId: sessionData.issueId } } }];
  }

} else if (sub === 'comment') {
  if (httpStatus >= 200 && httpStatus < 300) {
    body = 'Comment added to ' + arg0 + '.';
  } else if (httpStatus === 0 && !output.includes('CURL_ERROR')) {
    body = 'Comment added to ' + arg0 + '.';
  } else {
    body = 'Failed to add comment to ' + arg0 + ' (HTTP ' + httpStatus + '): ' + responseBody.substring(0, 200);
  }

} else {
  body = 'Unexpected response: ' + output.substring(0, 300);
}

const matrixBody = JSON.stringify({ msgtype: 'm.notice', body });
return [{ json: { matrixBody, isDone: false, triggerData: null } }];

