const stdout = $('Handle Mode').first().json.stdout || '';
const line = stdout.trim();
let body;

const descriptions = {
  'oc-cc': 'OpenClaw \u2192 Claude Code (default, cloud backend)',
  'oc-oc': 'OpenClaw \u2192 OpenClaw (fully local, offline safe)',
  'cc-cc': 'Claude Code only (legacy, bypass OpenClaw)',
  'cc-oc': 'n8n session \u2192 OpenClaw backend (cost saving)'
};

const tier1Map = {
  'oc-cc': 'OpenClaw (@openclaw) \u2014 qwen3-coder',
  'oc-oc': 'OpenClaw (@openclaw) \u2014 qwen3-coder',
  'cc-cc': 'Claude Code via n8n',
  'cc-oc': 'Claude Code via n8n'
};

const tier2Map = {
  'oc-cc': 'Claude Code via n8n',
  'oc-oc': 'OpenClaw \u2014 qwen3-coder',
  'cc-cc': 'Claude Code via n8n',
  'cc-oc': 'OpenClaw \u2014 qwen3-coder'
};

if (line.startsWith('STATUS:')) {
  const mode = line.split(':')[1];
  body = 'Current mode: ' + mode + '\n\n'
    + 'Tier 1 (frontend): ' + (tier1Map[mode] || 'Unknown') + '\n'
    + 'Tier 2 (backend):  ' + (tier2Map[mode] || 'Unknown') + '\n\n'
    + 'Available modes:\n'
    + '  oc-cc  ' + descriptions['oc-cc'] + '\n'
    + '  oc-oc  ' + descriptions['oc-oc'] + '\n'
    + '  cc-cc  ' + descriptions['cc-cc'] + '\n'
    + '  cc-oc  ' + descriptions['cc-oc'];
} else if (line.startsWith('SWITCHED:')) {
  const parts = line.split(':');
  const newMode = parts[1];
  const oldMode = parts[2];
  const lockState = parts[3];
  const switchMsgs = {
    'oc-cc': 'OpenClaw handles chat, Claude Code is the backend. Mention @claude directly to bypass OpenClaw.',
    'oc-oc': 'Fully local \u2014 OpenClaw + qwen3-coder. @claude is inactive in this mode.',
    'cc-cc': 'Claude Code handles chat directly. Mention @openclaw to reach OpenClaw.',
    'cc-oc': 'Claude Code frontend, OpenClaw backend. Mention @openclaw to reach OpenClaw directly.'
  };
  if (lockState === 'LOCKED') {
    body = '\u26a0\ufe0f Mode will apply to next session. Current session continues in ' + oldMode + '.\nNew mode: ' + newMode + ' \u2014 ' + (switchMsgs[newMode] || newMode);
  } else {
    body = '\u2713 Switched to ' + newMode + '. ' + (switchMsgs[newMode] || newMode);
  }
} else if (line.startsWith('UNKNOWN:')) {
  const sub = line.split(':')[1];
  body = 'Unknown mode: ' + sub + '\n\n'
    + 'Usage: !mode <mode>\n\n'
    + 'Modes:\n'
    + '  status  Show current mode\n'
    + '  oc-cc   OpenClaw \u2192 Claude Code (default)\n'
    + '  oc-oc   OpenClaw \u2192 OpenClaw (fully local)\n'
    + '  cc-cc   Claude Code only\n'
    + '  cc-oc   n8n session \u2192 OpenClaw backend';
} else {
  body = 'Error reading mode state.';
}

const matrixBody = JSON.stringify({ msgtype: 'm.notice', body });
return [{ json: { matrixBody, isDone: false, triggerData: null } }];

const stdout = $('Run OpenClaw').first().json.stdout || '';
const stderr = $('Run OpenClaw').first().json.stderr || '';
const raw = stdout.trim() || stderr.trim();

let responseText = 'OpenClaw did not return a response.';

try {
  const parsed = JSON.parse(raw);
  if (parsed.result && parsed.result.payloads && parsed.result.payloads.length > 0) {
    responseText = parsed.result.payloads.map(p => p.text).filter(Boolean).join('\n\n');
  } else if (parsed.error) {
    responseText = 'OpenClaw error: ' + (parsed.error.message || JSON.stringify(parsed.error));
  }
} catch (e) {
