    responseText = raw.substring(0, 4000);
  }
}

const plainText = '[OpenClaw] ' + responseText.substring(0, 4000);
const escaped = responseText.substring(0, 4000).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\n/g, '<br>');
