const stdout = $('Launch Resume Claude').first().json.stdout || '';
const issueId = $('Build Context').first().json.issueId || 'unknown';
const pidMatch = stdout.match(/PID:(\d+)/);
const pid = pidMatch ? parseInt(pidMatch[1]) : 0;
const sourceRoom = $('Extract Messages').first().json.sourceRoom || '!PVkZvHgyrtBVEbgpRt:matrix.example.net';

return [{ json: { pid, logFile: '/tmp/claude-run-' + issueId + '.jsonl', issueId, targetRoom: sourceRoom, startTime: Date.now() } }];

const stdout = $('Launch Start Claude').first().json.stdout || '';
const issueId = $('Format Issue Response').first().json.issueId || 'unknown';
const pidMatch = stdout.match(/PID:(\d+)/);
const pid = pidMatch ? parseInt(pidMatch[1]) : 0;

const ROOMS = { CUBEOS: '!iXTnQsFJahUquYPDdG:matrix.example.net', MESHSAT: '!miZJJDwFQZDkuMcBqL:matrix.example.net', IFRNLLEI01PRD: '!AOMuEtXGyzGFLgObKN:matrix.example.net' };
const targetRoom = ROOMS[issueId.split('-')[0]] || '!PVkZvHgyrtBVEbgpRt:matrix.example.net';

return [{ json: { pid, logFile: '/tmp/claude-run-' + issueId + '.jsonl', issueId, targetRoom, startTime: Date.now() } }];

const sourceRoom = $('Extract Messages').first().json.sourceRoom || '';
const prefix = $('Detect Command').first().json.prefix || '';

let slot;
if (prefix) {
  const projPrefix = prefix.split('-')[0];
  slot = (projPrefix === 'IFRNLLEI01PRD') ? 'infra-nl'
       : (projPrefix === 'IFRGRSKG01PRD') ? 'infra-gr'
       : (projPrefix === 'CUBEOS') ? 'cubeos'
       : (projPrefix === 'MESHSAT') ? 'meshsat'
       : 'dev';
} else {
  if (sourceRoom.includes('AOMuEtXGyzGFLgObKN')) slot = 'infra-nl';
  else if (sourceRoom.includes('NKosBPujbWMevzHaaM')) slot = 'infra-gr';
  else if (sourceRoom.includes('iXTnQsFJahUquYPDdG')) slot = 'cubeos';
  else if (sourceRoom.includes('miZJJDwFQZDkuMcBqL')) slot = 'meshsat';
  else slot = 'dev';
}
const lockFile = 'gateway.lock.' + slot;
return [{ json: { slot, lockFile } }];

const staticData = $getWorkflowStaticData('global');
const pa = staticData.pendingApprovals || {};
const now = Date.now();
const actions = [];

// Approval UX: MSC3381 poll instead of thumbs-up/down reaction (per operator
// request 2026-04-24). Sequence per pendingApproval:
//   1. On first bridge tick after the approval is tracked → post the poll.
//      (~30-60 s after the Runner's text message lands.)
//   2. At reminderMs (15 min standard / 60 min flapping) → post a text nudge
//      pointing back at the unvoted poll.
//   3. At timeoutMs (30 min standard / 4 h flapping) → auto-pause.
// Poll answers are id-tagged so the Extract Messages poll.response handler
// can distinguish approval polls from plan-selection polls:
//   id=approve   → _reactionType='approved'  (resume + execute)
//   id=reject    → _reactionType='rejected'  (resume + stop/rollback)
//   id=investigate → _reactionType='other'   (resume with 'operator needs more')

for (const [eventId, approval] of Object.entries(pa)) {
  const age = now - approval.timestamp;
  const isFlapping = (approval.flapCount || 0) >= 3;
  const timeoutMs = isFlapping ? 4 * 3600 * 1000 : 30 * 60 * 1000;
  const reminderMs = isFlapping ? 60 * 60 * 1000 : 15 * 60 * 1000;
  const timeoutLabel = isFlapping ? '4h' : '30m';
  const reminderLabel = isFlapping ? '1h' : '15m';

  if (age > timeoutMs) {
    const body = '⏰ Approval for ' + approval.issueId + ' timed out (' + timeoutLabel + '). Session auto-paused. Use !session resume to continue.';
    actions.push({
      roomId: approval.roomId,
      issueId: approval.issueId,
      shouldPause: true,
      matrixEventType: 'm.room.message',
      matrixBody: JSON.stringify({ msgtype: 'm.notice', body })
    });
    delete pa[eventId];
    continue;
  }

  if (!approval.pollPosted) {
    const pollQuestion = '⏰ Approval pending for ' + approval.issueId + ' — your call?';
    const pollBody = {
      'org.matrix.msc3381.poll.start': {
        kind: 'org.matrix.msc3381.poll.disclosed',
        max_selections: 1,
        question: {
          'org.matrix.msc1767.text': pollQuestion,
          body: pollQuestion,
          msgtype: 'm.text'
        },
        answers: [
          { id: 'approve',     'org.matrix.msc1767.text': 'Approve — proceed' },
          { id: 'reject',      'org.matrix.msc1767.text': 'Reject — stop' },
          { id: 'investigate', 'org.matrix.msc1767.text': 'Investigate further first' }
        ]
      },
      // Fallback body for clients that don't render polls
      'org.matrix.msc1767.text': pollQuestion + '\n- Approve\n- Reject\n- Investigate further',
      body: pollQuestion
    };
    actions.push({
      roomId: approval.roomId,
      issueId: approval.issueId,
      shouldPause: false,
      matrixEventType: 'org.matrix.msc3381.poll.start',
      matrixBody: JSON.stringify(pollBody)
    });
    approval.pollPosted = true;
    continue;
  }

  if (age > reminderMs && !approval.reminded) {
    const body = '⏰ Still pending — please vote on the approval poll for ' + approval.issueId + ' (' + reminderLabel + ' since it was posted).';
    actions.push({
      roomId: approval.roomId,
      issueId: approval.issueId,
      shouldPause: false,
      matrixEventType: 'm.room.message',
      matrixBody: JSON.stringify({ msgtype: 'm.notice', body })
    });
    approval.reminded = true;
  }
}

if (actions.length === 0) return [];
return actions.map(a => ({ json: a }));

