    return [{ json: { matrixBody, isDone: true, triggerData: { sessionId: sessionData.sessionId, issueId: sessionData.issueId } } }];
  }

} else if (sub === 'comment') {
  if (httpStatus >= 200 && httpStatus < 300) {
    body = 'Comment added to ' + arg0 + '.';
  } else if (httpStatus === 0 && !output.includes('CURL_ERROR')) {
