parameters.jsCode:
const stdout = $input.first().json.stdout || '';
const stderr = $input.first().json.stderr || '';
const sub = $('Detect Command').first().json.sub || '';
const args = $('Detect Command').first().json.args || [];
const arg0 = (args[0] || '').toLowerCase();
const output = (stdout.trim() || stderr.trim());

let body = '';

const STATUS_SYM = {passed: '\u2713', success: '\u2713', failed: '\u2717', running: '\u27f3', pending: '\u25cb', canceled: '\u25cb', skipped: '\u25cb'};

function relTime(iso) {
  if (!iso) return '?';
  const diff = Math.floor((Date.now() - new Date(iso).getTime()) / 1000);
  if (diff < 0) return 'just now';
  if (diff < 60) return diff + 's ago';
  if (diff < 3600) return Math.floor(diff / 60) + 'm ago';
  if (diff < 86400) return Math.floor(diff / 3600) + 'h ago';
  return Math.floor(diff / 86400) + 'd ago';
}

function fmtDur(pipeline) {
  if (!pipeline.created_at || !pipeline.finished_at) return '\u2014';
  const secs = Math.floor((new Date(pipeline.finished_at) - new Date(pipeline.created_at)) / 1000);
  if (secs < 0) return '\u2014';
  const m = Math.floor(secs / 60);
  const s = secs % 60;
  return m + 'm ' + String(s).padStart(2, '0') + 's';
}

if (output.startsWith('USAGE') || !sub) {
  body = '!pipeline subcommands:\n'
    + 'status           \u2014 All repos latest pipeline status\n'
    + 'status <repo>    \u2014 Last 5 pipelines for a specific repo\n'
    + 'logs <repo>      \u2014 Logs from latest failed pipeline\n'
    + 'retry <repo>     \u2014 Retry latest failed pipeline\n'
    + 'Repos: api, dashboard, hal, coreapps, releases, meshsat';

} else if (output.startsWith('UNKNOWN_REPO:')) {
  body = 'Unknown repo: ' + output.split(':')[1] + '. Valid repos: api, dashboard, hal, coreapps, releases, meshsat';

} else if (output.startsWith('NEED_REPO')) {
  body = 'Usage: !pipeline ' + sub + ' <repo>\nRepos: api, dashboard, hal, coreapps, releases, meshsat';

} else if (output.startsWith('UNKNOWN_SUB:')) {
  body = 'Unknown pipeline command: ' + output.split(':')[1] + '\n\n' +
    '!pipeline commands:\n' +
    'status           \u2014 All repos latest pipeline status\n' +
    'status <repo>    \u2014 Last 5 pipelines for a specific repo\n' +
    'logs <repo>      \u2014 Logs from latest failed pipeline\n' +
    'retry <repo>     \u2014 Retry latest failed pipeline\n' +
    'Repos: api, dashboard, hal, coreapps, releases, meshsat';

} else if (output.startsWith('API_ERROR:')) {
  body = 'GitLab API error: ' + output.split(':').slice(1).join(':');

} else if (sub === 'status' && !arg0) {
  const lines = output.split('\n').filter(l => l.includes('|'));
  const results = [];
  for (const line of lines) {
    const pipeIdx = line.indexOf('|');
    const name = line.substring(0, pipeIdx).trim();
    const jsonStr = line.substring(pipeIdx + 1).trim();
    try {
      const pipelines = JSON.parse(jsonStr);
      if (pipelines && pipelines.length > 0) {
        const p = pipelines[0];
        const sym = STATUS_SYM[p.status] || '?';
        results.push(name.padEnd(11) + '#' + String(p.id).padEnd(8) + sym + ' ' + (p.status || '?').padEnd(10) + (p.ref || '?').padEnd(10) + relTime(p.updated_at));
      } else {
        results.push(name.padEnd(11) + '\u2014');
      }
    } catch (e) {
      results.push(name.padEnd(11) + '(error)');
    }
  }
  body = 'Pipeline status:\n' + results.join('\n') + '\n\nType !pipeline logs <repo> to see failure details.';

} else if (sub === 'status' && arg0) {
  const lines = output.split('\n');
  const jsonStr = lines.filter(l => !l.startsWith('REPO:')).join('\n');
  try {
    const pipelines = JSON.parse(jsonStr);
    if (!pipelines.length) {
      body = 'No pipelines found for ' + arg0 + '.';
    } else {
      const rows = pipelines.map(p => {
        const sym = STATUS_SYM[p.status] || '?';
        return '#' + String(p.id).padEnd(8) + sym + ' ' + (p.status || '?').padEnd(10) + (p.ref || '?').padEnd(14) + relTime(p.updated_at).padEnd(10) + fmtDur(p);
      });
      body = arg0 + ' \u2014 last ' + pipelines.length + ' pipelines:\n' + rows.join('\n');
    }
  } catch (e) {
    body = 'Error parsing pipeline data: ' + jsonStr.substring(0, 200);
  }

} else if (sub === 'logs') {
  if (output.startsWith('NO_FAILED')) {
    body = 'No failed pipelines found for ' + arg0 + '.';
  } else if (output.startsWith('NO_FAILED_JOBS')) {
    body = 'Pipeline failed but no failed jobs found for ' + arg0 + '.';
  } else {
    const lines = output.split('\n');
    const pipelineMatch = lines.find(l => l.startsWith('PIPELINE:'));
    const pipelineId = pipelineMatch ? pipelineMatch.split(':')[1] : '?';
    const parts = [];
    let currentJob = null;
    let inTrace = false;
    let traceLines = [];

    for (const line of lines) {
      if (line.startsWith('JOB:')) {
        if (currentJob) {
          parts.push(currentJob);
        }
        const jobParts = line.split(':');
        currentJob = { id: jobParts[1], name: jobParts[2], stage: jobParts[3], trace: '', link: '' };
      } else if (line === 'TRACE_START') {
        inTrace = true;
        traceLines = [];
      } else if (line === 'TRACE_END') {
        inTrace = false;
        if (currentJob) currentJob.trace = traceLines.join('\n');
      } else if (line.startsWith('LINK:') && currentJob) {
        currentJob.link = line.substring(5);
      } else if (inTrace) {
        traceLines.push(line);
      }
    }
    if (currentJob) parts.push(currentJob);

    if (parts.length === 0) {
      body = 'No failed job details available for ' + arg0 + '.';
    } else {
      const sections = parts.map(j => {
        let s = 'Job: ' + j.name + ' (failed)\nStage: ' + j.stage + '\n--- last 30 lines ---\n';
        s += j.trace.substring(0, 3000);
        if (j.link) s += '\nJob link: ' + j.link;
        return s;
      });
      body = arg0 + ' \u2014 pipeline #' + pipelineId + ' failed:\n\n' + sections.join('\n\n');
    }
  }

} else if (sub === 'retry') {
  if (output.startsWith('NO_FAILED')) {
    body = 'No failed pipeline to retry for ' + arg0 + '.';
  } else if (output.startsWith('RETRIED:')) {
    body = 'Retrying ' + arg0 + ' pipeline #' + output.split(':')[1] + '...';
  } else if (output.startsWith('RETRY_ERROR:')) {
    body = 'Failed to retry: ' + output.split(':').slice(1).join(':');
  } else {
    body = 'Unexpected response: ' + output.substring(0, 300);
  }

} else {
  body = 'Unexpected response: ' + output.substring(0, 300);
}

const matrixBody = JSON.stringify({ msgtype: 'm.notice', body });
return [{ json: { matrixBody, isDone: false, triggerData: null } }];

