    + 'Endpoint: https://ollama.example.net\n'
    + 'All claude processes restarted.\n'
    + '\n'
    + 'Next session will use the local model.\n'
    + 'Use !online to switch back to Anthropic.';

} else if (sub === 'online') {
  body = '\u2601\ufe0f  Switched to ONLINE mode\n'
    + 'Model: Anthropic cloud API\n'
    + 'All claude processes restarted.\n'
    + '\n'
    + 'Next session will use the Anthropic API.\n'
    + 'Use !offline to switch to local Ollama.';

} else if (sub === 'status') {
  const vals = {};
  output.split('\n').forEach(line => {
    const idx = line.indexOf(':');
    if (idx > 0) vals[line.substring(0, idx)] = line.substring(idx + 1).trim();
  });
  const mode = vals.MODE || 'unknown';
  const modeIcon = mode === 'OFFLINE' ? '\u26a1' : '\u2601\ufe0f';
  body = '\ud83d\udce1 Gateway Status\n'
    + 'Mode    : ' + modeIcon + ' ' + mode + '\n'
    + 'Model   : ' + (vals.MODEL || '?') + '\n'
    + (vals.ENDPOINT ? 'Endpoint: ' + vals.ENDPOINT + '\n' : '')
    + 'Session : ' + (vals.SESSION || 'none');

} else {
  body = 'Unexpected response: ' + output.substring(0, 300);
