const stdout = $input.first().json.stdout || '';
const stderr = $input.first().json.stderr || '';
const output = stdout.trim() || stderr.trim();

function extract(text, label) {
  const re = new RegExp(label + '_START\\n([\\s\\S]*?)\\n' + label + '_END');
  const m = text.match(re);
  return m ? m[1].trim() : '?';
}

const lock = extract(output, 'LOCK');
const sessionsRaw = extract(output, 'SESSIONS');
const queueCount = extract(output, 'QUEUE');
const cooldown = extract(output, 'COOLDOWN');
const modeLines = extract(output, 'MODE').split('\n');
const procs = extract(output, 'PROCS');

// Parse sessions
let sessionsInfo = 'none';
try {
  const sessions = JSON.parse(sessionsRaw);
  if (sessions.length > 0 && sessions[0].issue_id) {
    sessionsInfo = sessions.map(s => {
      const current = s.is_current ? ' [CURRENT]' : '';
      const paused = s.paused ? ' [PAUSED]' : '';
      return s.issue_id + ': ' + (s.issue_title || '?').substring(0, 40) + current + paused + ' (msgs: ' + s.message_count + ')';
    }).join('\n  ');
  }
} catch(e) { sessionsInfo = sessionsRaw.substring(0, 200); }

// Parse mode
const mode = modeLines[0] || '?';
const modeDetail = modeLines.length > 1 ? modeLines.slice(1).join(' / ') : '';

let body = 'Gateway Debug Dump\n'
  + '\n'
  + 'Lock    : ' + lock + '\n'
  + 'Sessions: ' + sessionsInfo + '\n'
  + 'Queue   : ' + queueCount + ' message(s)\n'
  + 'Cooldown: ' + cooldown + '\n'
  + 'Mode    : ' + mode + (modeDetail ? ' (' + modeDetail + ')' : '') + '\n'
  + 'Procs   : ' + procs;

const matrixBody = JSON.stringify({ msgtype: 'm.notice', body });
return [{ json: { matrixBody, isDone: false, triggerData: null } }];

function applyInline(text) {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/\*(.+?)\*/g, '<em>$1</em>')
    .replace(/`([^`]+)`/g, '<code>$1</code>')
    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');
}

const stdout = $input.first().json.stdout || '';
const stderr = $input.first().json.stderr || '';
const issueId = $('Format Issue Response').first().json.issueId;
const summary = $('Format Issue Response').first().json.summary || '';

const output = stdout.trim() || stderr.trim();

let result = '';
let sessionId = '';
let hasValidSession = false;

if (!output) {
  result = 'Claude returned no output. The lock has been acquired — try sending a message to continue, or use !session cancel to reset.';
} else {
  try {
    const parsed = JSON.parse(output);
    result = parsed.result || '';
    sessionId = parsed.session_id || '';
    if (parsed.is_error) {
      result = 'Claude error: ' + (parsed.result || parsed.error || 'unknown error');
    }
    if (!result) {
      result = 'Claude returned an empty result. Session may still be valid — try sending a follow-up message.';
    }
    if (sessionId) {
      hasValidSession = true;
    }
  } catch (e) {
    result = output.substring(0, 2000);
  }
}

// Add @dominicus mention when awaiting approval
const needsApproval = /approv|waiting|human|confirm/i.test(result);
const mentionPill = needsApproval ? '<a href="https://matrix.to/#/@dominicus:matrix.example.net">@dominicus</a> ' : '';
const mentionPlain = needsApproval ? '@dominicus ' : '';

const plainText = mentionPlain + '**' + issueId + '** — Session started\n\n' + result.substring(0, 4000);
const htmlLines = result.substring(0, 4000).split('\n').map(l => applyInline(l)).join('<br>');
const htmlText = mentionPill + '<p><strong>' + issueId + '</strong> — Session started</p><p>' + htmlLines + '</p>';

const matrixBody = JSON.stringify({
  msgtype: 'm.text',
  body: plainText,
  format: 'org.matrix.custom.html',
  formatted_body: htmlText
});

return [{ json: { matrixBody, result, sessionId, issueId, summary, hasValidSession } }];

